export const ModelResponseConfigurationSchema = {
  type: 'object',
  properties: {
    format: {
      oneOf: [
        { type: 'null' },
        {
          $ref: '#/$defs/ModelResponseFormat',
          description:
            'An object specifying the format that the model must output. Specify `{ "type": "json_object" }` for JSON output, or `{ "type": "json_schema", "json_schema": {...} }` for structured outputs. If `{ \\"type\\": \\"text\\" }`, the model will return a text response.',
        },
      ],
    },
  },
  $defs: {
    ModelResponseFormat: {
      oneOf: [
        {
          type: 'object',
          description: 'Specify text response format, always `"text"`.',
          required: ['type'],
          properties: { type: { type: 'string', enum: ['text'] } },
        },
        {
          type: 'object',
          description:
            'Specify json_object response format, always `json_object`. Used for backward compatibility. Prefer to use `"json_schema"` instead of this.',
          required: ['type'],
          properties: { type: { type: 'string', enum: ['json_object'] } },
        },
        {
          type: 'object',
          description:
            'Specify json_schema response format with a given schema. Type is always `"json_schema"`.',
          required: ['schema', 'type'],
          properties: {
            description: {
              type: ['string', 'null'],
              description: 'Only included for compatibility.',
            },
            name: {
              type: ['string', 'null'],
              description: 'Only included for compatibility.',
            },
            schema: {
              description:
                'A json schema representing the desired response schema.',
            },
            strict: {
              type: ['boolean', 'null'],
              description: 'Only included for compatibility.',
            },
            type: { type: 'string', enum: ['json_schema'] },
          },
        },
      ],
      description: 'Response format parameter for structured outputs.',
    },
  },
} as const

